"""Platform icon loader — returns QPixmap for each platform brand icon."""

import os
import sys
import base64
from functools import lru_cache

from PySide6.QtGui import QPixmap
from PySide6.QtCore import Qt, QSize
from PySide6.QtWidgets import QLabel


def _base_dir() -> str:
    if getattr(sys, "frozen", False):
        return sys._MEIPASS
    return os.path.dirname(os.path.dirname(os.path.abspath(__file__)))


_ICON_FILES = {
    "Cursor": "cursor.png",
    "Cursor Pro": "cursor.png",
    "Kiro": "kiro.png",
    "Codex": "codex.png",
    "Claude Code": "claude.png",
    "Gemini": "gemini.png",
    "OpenClaw": "openclaw.png",
    "Windsurf": "windsurf.png",
}

# Embedded fallback icons (base64) — used when the file is missing in older builds
_EMBEDDED_ICONS = {
    "windsurf.png": "",
}


@lru_cache(maxsize=32)
def platform_pixmap(name: str, size: int = 24) -> QPixmap:
    fname = _ICON_FILES.get(name, "")
    if not fname:
        return QPixmap()
    path = os.path.join(_base_dir(), "assets", "icons", fname)
    pm = QPixmap()
    if os.path.exists(path):
        pm.load(path)
    if pm.isNull() and fname in _EMBEDDED_ICONS:
        data = base64.b64decode(_EMBEDDED_ICONS[fname])
        pm.loadFromData(data)
    if pm.isNull():
        return pm
    return pm.scaled(
        QSize(size, size),
        Qt.AspectRatioMode.KeepAspectRatio,
        Qt.TransformationMode.SmoothTransformation,
    )


def platform_icon_label(name: str, size: int = 24) -> QLabel:
    lbl = QLabel()
    lbl.setFixedSize(size, size)
    lbl.setStyleSheet("background: transparent; border: none;")
    pm = platform_pixmap(name, size)
    if not pm.isNull():
        lbl.setPixmap(pm)
    else:
        lbl.setText(name[:1])
    return lbl
